INSERT INTO locations (id, title, region, description, best_time, equipment, my_tip, coordinates, published, created_at, related_guides, when_to_visit, recommended_gear) VALUES (
  'roma',
  'רומא — הנצח שאפשר לצלם',
  'איטליה',
  'רומא היא אחת הערים הפוטוגרפיות ביותר בעולם — כל פינה מחכה לצלם. הפנתאון (מ-125 לספירה!) הוא אחת מנקודות הצילום המדהימות שידעתי — האוקולוס שבמרכז הגג שופך קרן אור ישירות על הרצפה השיישית. הקולוסאום בשעת הזהב זוהר בכתום עמוק. מדרגות הוותיקן הספירליות הן אחד הצילומים האיקוניים ביותר שקיימים. ופיאצה נבונה עם הכיפות הזהובות של סנטה אניסה בשקיעה — מראה שאי אפשר לשכוח.',
  'שעת הזהב — האבן הרומית מקבלת גוון זהוב-כתום מדהים לפני שקיעה. בוקר מוקדם — לפני שהתיירים מציפים את המקום — הוא הזמן הטוב לפנתאון ולקולוסאום.',
  'עדשה רחבה 16-35mm לארכיטקטורה ופנים, טלה 70-200mm לפרטים ועיטורים, חצובה לצילומי לילה ולאורות עיר',
  'בפנתאון — הגיעו בסביבות 11 בבוקר כשהשמש גבוהה ויוצרת קרן אור דרמטית דרך האוקולוס על הרצפה. למדרגות הוותיקן — פתחו עם פתיחת המוזיאון (9 בבוקר) לפני שמגיעים התיירים. לקולוסאום — עמדו ממזרח-דרום בשעת הזהב לאור הכי דרמטי.',
  '41.9028,12.4964',
  1,
  '2026-05-15T16:00:00.000Z',
  '["/camera/lenses/","/camera/light/","/camera/composition/"]',
  '{"summer":{"rating":"ok","note":"חם מאוד, עמוס בתיירים. צאו לפנות בוקר או אחרי 6 בערב."},"fall":{"rating":"good","note":"ספטמבר-אוקטובר — אור נפלא, פחות אנשים, הטמפרטורה נעימה."},"winter":{"rating":"good","note":"דצמבר-פברואר — שקט יחסית, אור רך ונמוך, שמיים דרמטיים."},"spring":{"rating":"good","note":"מרץ-מאי — פריחה, אור נפלא, לפני עיקר עונת התיירות."}}',
